func (this *CoinbaseinternationalCore) ParsePosition(position any, optionalArgs ...any) any {
	//
	//    {
	//       "symbol":"BTC-PERP",
	//       "instrument_id":"114jqr89-0-0",
	//       "instrument_uuid":"b3469e0b-222c-4f8a-9f68-1f9e44d7e5e0",
	//       "vwap":"52482.3",
	//       "net_size":"0",
	//       "buy_order_size":"0.001",
	//       "sell_order_size":"0",
	//       "im_contribution":"0.2",
	//       "unrealized_pnl":"0",
	//       "mark_price":"52406.8",
	//       "entry_vwap":"52472.9"
	//    }
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var marketId any = this.SafeString(position, "symbol")
	var quantity any = this.SafeString(position, "net_size")
	market = this.SafeMarket(marketId, market, "-")
	var side any = "long"
	if IsTrue(Precise.StringLe(quantity, "0")) {
		side = "short"
		quantity = Precise.StringMul("-1", quantity)
	}
	return this.SafePosition(map[string]any{
		"info":                        position,
		"id":                          this.SafeString(position, "id"),
		"symbol":                      GetValue(market, "symbol"),
		"entryPrice":                  nil,
		"markPrice":                   this.SafeNumber(position, "mark_price"),
		"notional":                    nil,
		"collateral":                  nil,
		"unrealizedPnl":               this.SafeNumber(position, "unrealized_pnl"),
		"side":                        side,
		"contracts":                   this.ParseNumber(quantity),
		"contractSize":                this.SafeNumber(market, "contractSize"),
		"timestamp":                   nil,
		"datetime":                    nil,
		"hedged":                      nil,
		"maintenanceMargin":           nil,
		"maintenanceMarginPercentage": nil,
		"initialMargin":               this.SafeNumber(position, "im_contribution"),
		"initialMarginPercentage":     nil,
		"leverage":                    nil,
		"liquidationPrice":            nil,
		"marginRatio":                 nil,
		"marginMode":                  nil,
		"percentage":                  nil,
	})
}

